for d in 1natsu-auto-resolve-conflicts 1natsu-pair-resolve-conflicts; do
  echo "=== $d ===";
  # strip the 'description:' key, then count remaining ': ' occurrences in the value
  val=$(grep -m1 "^description:" "skills/$d/SKILL.md" | sed -E 's/^description://');
